import xml.etree.ElementTree as ET

def validate_xml(xml_file):
    try:
        # Parse the XML file
        tree = ET.parse(xml_file)
        root = tree.getroot()
        
        # Validate the XML structure (example validation logic)
        if root.tag != 'document':
            raise ValueError("Root element must be 'document'")
        
        for child in root:
            if child.tag not in ['section', 'subsection']:
                raise ValueError(f"Invalid tag: {child.tag}")
        
        print("XML is valid.")
    except ET.ParseError as e:
        print(f"XML parsing error: {e}")
    except ValueError as e:
        print(f"Validation error: {e}")

# Example usage
# validate_xml('example.xml')